def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        complexity_factor = 0
        if ratio < 0.05:
            for a in range(1, 15):
                term = np.tanh(ratio * a) * (a ** 3.1)
                if a % 4 == 0:
                    term *= 0.85
                else:
                    term *= 1.15
                score += term
            if (capacity + item) % 2 == 0 and (capacity - item) % 7 == 0:
                score *= 0.75
            if score > 12:
                score /= 3.1
            for j in range(3):
                complexity_factor += (np.sin(ratio * (j+1) * 10) + np.cos(capacity / (j+1))) * (j+1)
            score += complexity_factor / 4
        elif 0.05 <= ratio < 0.25:
            prod = 1
            for n in range(1, int(capacity)+5):
                prod *= (ratio + (n**0.5) / (n + 2))
                if prod > 1e8:
                    prod = np.log1p(prod)
                    break
            mod_val = int(prod*1.37) % 400
            score += np.sqrt(ratio * mod_val + 2)
            if int(capacity) % 5 == 0 or (item * 7) % 4 == 0:
                score += 6.3
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                frac = ((ratio * x**3) % 1)
                extra_sum += frac * (x ** 2.3)
            score += extra_sum / 5.2
            for k in range(2,5):
                score += ((ratio * k) % 1)**1.4 * (k**1.8)
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 10):
                increment = (ratio ** (m + 1.5)) * (m ** 3) / ((m + 1) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -6:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 5 == 0:
                score *= 1.35
            if score > 18:
                score /= 3.4
            for p in range(1, 4):
                score += np.tanh(remainder / (p + 0.5)) * (p ** 2)
        elif 0.55 < ratio <= 0.85:
            penalty_base = 0
            diff = ratio - 0.55
            for p in range(1, 14):
                penalty_base += ((diff) ** p) * (p ** 1.8)
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) ** 1.3
                    break
            score = penalty_base * 10
            if capacity < item * 1.02:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 13 == 0):
                score -= 8.5
            if score < 0:
                score *= -1.8
                score += 8
            if score > 110:
                score = 110
            for z in range(1, 5):
                score += ((diff / (z + 1.2)) % 1) * (z * 2.1)
        elif 0.85 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 2.9) / (q + 2)
            score = penalty_ext * 25
            if capacity < item * 1.15:
                score += 25
            if (int(capacity * 6) % 8 == 0) and (int(item * 11) % 5 == 0):
                score -= 12
            for z in range(1, 7):
                score += ((diff / (z + 0.8)) % 1) * (z * 2.3)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1400:
                score = 1400
            for tt in range(3, 8):
                score += np.sin(diff * tt) * (tt ** 1.3)
        else:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 12000:
                    term = np.log1p(term) * 2.5
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 17) % 6 == 0) and (int(item * 23) % 7 == 0):
                score -= 15
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
            for vv in range(1, 5):
                score += np.tanh(diff * vv) * (vv ** 2)
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.4)
            score += np.log1p(score * 0.1)
        elif capacity < 3:
            score *= 3.1
            score -= ratio * 4
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count*1.5) - median_val * 0.8
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
